import{c as t,Q as s,j as o,m as a}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"10 GitHub Repos Most Claude Code Devs Have Never Touched — @0x_kaize","description":"","frontmatter":{"title":"10 GitHub Repos Most Claude Code Devs Have Never Touched — @0x_kaize","author":"kaize（@0x_kaize）","date":"2026-04-18T00:00:00.000Z","source":"https://x.com/0x_kaize/status/2045580955759309131","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-18-@0x_kaize-309131.md","filePath":"research/tweets/2026-04-18-@0x_kaize-309131.md","lastUpdated":1779894392000}'),r={name:"research/tweets/2026-04-18-@0x_kaize-309131.md"};function l(i,e,n,d,p,u){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_10-github-repos-most-claude-code-devs-have-never-touched-—-0x-kaize" tabindex="-1">10 GitHub Repos Most Claude Code Devs Have Never Touched — @0x_kaize <a class="header-anchor" href="#_10-github-repos-most-claude-code-devs-have-never-touched-—-0x-kaize" aria-label="Permalink to &quot;10 GitHub Repos Most Claude Code Devs Have Never Touched — @0x_kaize&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/0x_kaize/status/2045580955759309131" target="_blank" rel="noreferrer">https://x.com/0x_kaize/status/2045580955759309131</a><strong>作者</strong>：kaize（@0x_kaize） <strong>發布日期</strong>：2026-04-18 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文（長推文 note_tweet） <strong>統計</strong>：155 likes · 12 retweets · 193 bookmarks · 17,742 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>90% of DEVS using CLAUDE Code have never touched these repos</p><p>I SPENT 3 weeks digging through github</p><p>here are 10 REPOS that will make you 10x better overnight:</p><p>1/ awesome-claude-code</p><p>The definitive curated list of skills, hooks, slash-commands, agent orchestrators and plugins</p><ul><li>28.5k+ stars, the ecosystem&#39;s main index</li><li>only Claude itself is allowed to submit PRs</li><li>categorized by skills, hooks, commands, orchestrators, plugins</li></ul><p>repo: <a href="https://github.com/hesreallyhim/awesome-claude-code" target="_blank" rel="noreferrer">https://github.com/hesreallyhim/awesome-claude-code</a></p><p>2/ awesome-claude-skills (ComposioHQ)</p><p>Curated list of 50+ Claude skills for real-world automation</p><ul><li>PostgreSQL, deep research, CSV analysis, root-cause tracing</li><li>organized by category and workflow type</li><li>works across Claude Code, Codex, Cursor, Gemini CLI</li></ul><p>repo: <a href="https://github.com/ComposioHQ/awesome-claude-skills" target="_blank" rel="noreferrer">https://github.com/ComposioHQ/awesome-claude-skills</a></p><p>3/ awesome-claude-plugins (ComposioHQ)</p><p>Curated plugins that extend Claude Code via the plugin system</p><ul><li>custom commands, agents, hooks and MCP servers</li><li>includes connect-apps, frontend-design, artifacts-builder, theme-factory</li><li>install via /plugin marketplace add</li></ul><p>repo: <a href="https://github.com/ComposioHQ/awesome-claude-plugins" target="_blank" rel="noreferrer">https://github.com/ComposioHQ/awesome-claude-plugins</a></p><p>4/ awesome-claude-prompts</p><p>A huge collection of optimized Claude prompts</p><ul><li>4.2k+ stars, 413 forks</li><li>XML-structured prompts and advanced techniques</li><li>covers dev workflows, business and creative tasks</li></ul><p>repo: <a href="https://github.com/langgptai/awesome-claude-prompts" target="_blank" rel="noreferrer">https://github.com/langgptai/awesome-claude-prompts</a></p><p>5/ awesome-claude</p><p>All-around list of everything Anthropic Claude related</p><ul><li>courses, guides, desktop apps and articles</li><li>covers MCP, BMAD method, Claude Code tips</li><li>good starting point for newcomers</li></ul><p>repo: <a href="https://github.com/alvinunreal/awesome-claude" target="_blank" rel="noreferrer">https://github.com/alvinunreal/awesome-claude</a></p><p>6/ awesome-agent-skills (VoltAgent)</p><p>1000+ agent skills from real engineering teams</p><ul><li>not AI-generated slop, real battle-tested skills</li><li>works with Claude Code, Codex, Gemini CLI, Cursor</li><li>includes Notion, WhatsApp, NotebookLM, memory skills</li></ul><p>repo: <a href="https://github.com/VoltAgent/awesome-agent-skills" target="_blank" rel="noreferrer">https://github.com/VoltAgent/awesome-agent-skills</a></p><p>7/ awesome-claude-code-subagents (VoltAgent)</p><p>Hand-picked subagents for every stack and task</p><ul><li>domain-specific expertise bundles</li><li>production-ready components</li><li>integrates with most coding agents</li></ul><p>repo: <a href="https://github.com/VoltAgent/awesome-claude-code-subagents" target="_blank" rel="noreferrer">https://github.com/VoltAgent/awesome-claude-code-subagents</a></p><p>8/ awesome-claude-code-plugins (ccplugins)</p><p>Focused list of Claude Code plugins only</p><ul><li>slash commands, subagents, MCP servers, hooks</li><li>install commands included for each</li><li>enables hosting your own plugin marketplace</li></ul><p>repo: <a href="https://github.com/ccplugins/awesome-claude-code-plugins" target="_blank" rel="noreferrer">https://github.com/ccplugins/awesome-claude-code-plugins</a></p><p>9/ obra/superpowers</p><p>The most popular community skills library for Claude Code</p><ul><li>148k+ stars</li><li>structured workflow: brainstorm -&gt; spec -&gt; plan -&gt; TDD -&gt; review -&gt; merge</li><li>subagent orchestration with fresh contexts per task</li></ul><p>repo: <a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">https://github.com/obra/superpowers</a></p><p>10/ Claude-Flow</p><p>Enterprise-grade AI orchestration platform</p><ul><li>11.4k+ stars</li><li>reshapes how developers build with AI</li><li>multi-agent orchestration with persistent memory</li></ul><p>repo: <a href="https://github.com/ruvnet/claude-flow" target="_blank" rel="noreferrer">https://github.com/ruvnet/claude-flow</a></p><p>This is just a small selection of the repositories I&#39;ve managed to find, more to come in future posts</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：整理 10 個 Claude Code 生態系 GitHub repo 精選清單，涵蓋 skills、plugins、subagents 與 orchestration 框架。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>awesome-claude-code</strong>（hesreallyhim）是生態系主索引，28.5k stars，僅允許 Claude 本身提交 PR，涵蓋 skills / hooks / commands / orchestrators / plugins 分類。</li><li><strong>ComposioHQ 雙 repo</strong>（awesome-claude-skills + awesome-claude-plugins）提供 50+ 生產就緒 skills 與 plugin 擴充，跨 Claude Code / Codex / Cursor / Gemini CLI 可用。</li><li><strong>VoltAgent 雙 repo</strong>（awesome-agent-skills + awesome-claude-code-subagents）強調非 AI 生成、真實工程團隊驗證的 skills 與 subagent bundles，1000+ items。</li><li><strong>obra/superpowers</strong> 號稱最熱門社群 skills library，148k stars，有結構化工作流（brainstorm → spec → plan → TDD → review → merge）與 subagent 新 context 隔離。</li><li><strong>Claude-Flow</strong>（ruvnet）定位企業級多 agent 編排平台，11.4k stars，含持久記憶。</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>awesome-claude-code：28.5k stars</li><li>awesome-claude-prompts：4.2k stars，413 forks</li><li>obra/superpowers：148k stars（異常高，需驗證）</li><li>Claude-Flow：11.4k stars</li><li>awesome-agent-skills：1000+ skills</li><li>所有 repo 均聲稱跨工具相容（Claude Code / Codex / Cursor / Gemini CLI）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>148k stars 存疑</strong>：obra/superpowers 聲稱 148k stars 遠超 awesome-claude-code 的 28.5k，但這個數量在 GitHub 極為罕見（僅有 freeCodeCamp / VS Code 等少數 repo 達此量級），高度可疑，需實際驗證。</li><li><strong>內容品質差異大</strong>：部分 repo（VoltAgent 強調「非 AI 生成」）暗示其他清單存在 AI 灌水問題；cc-workspace 整合前應先評估各 skills 的實際品質，而非依星數決策。</li><li><strong>對 cc-workspace 的應用</strong>：awesome-claude-code 和 ComposioHQ skills repo 最值得探索，可作為 <code>.claude/skills/</code> 新 skill 的靈感來源；但本 workspace 已有嚴格的 skill-authoring 規範，外部 skill 需通過 <code>evaluate-import</code> 審查再整合。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>提供可直接 clone 驗證的具體 repo 清單，evaluate-import 可用</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>策展清單型內容，無新觀點，但做了聚合工作</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>僅有星數與功能描述，obra/superpowers 148k 數字存疑，無獨立驗證</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>停留在介紹層次，無安裝示範、無比較測試</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>Claude Code 生態系通用，不限特定 stack</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.5/10</strong></td><td>7×0.3+5×0.2+4×0.2+4×0.15+7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 5.5 低於閾值 6，且內容為策展清單而非可直接套用的方法論；部分數據（obra stars）可信度待確認，建議有需要時手動逐一驗證各 repo。</p>',61)])])}const g=t(r,[["render",l]]);export{h as __pageData,g as default};
